'use client'
import { cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { cloneElement, isValidElement, useRef, type ReactElement, type ReactNode } from 'react'
import styles from './app-shell.module.css'

/** Props AppShell injects into a {@link ShellHeader}-shaped header element. */
interface HeaderMenuProps {
  onMenuClick?: (() => void) | undefined
  menuExpanded?: boolean
}

export interface AppShellProps {
  /**
   * Top bar — typically a `<ShellHeader>`. If it is a React element, AppShell
   * binds its burger (`onMenuClick`/`menuExpanded`) to the nav open state so the
   * header button toggles the nav out of the box.
   */
  header: ReactNode
  /** Side navigation — typically a `<SideNav>`. Fills full height and scrolls internally. */
  nav?: ReactNode
  /** Main content. Lives in the single scroll container. */
  children: ReactNode
  /** Optional footer pinned below the content area. */
  footer?: ReactNode
  /** Controlled nav open/visible state. Omit for uncontrolled (see `defaultOpen`). */
  open?: boolean
  /** Initial open state when uncontrolled. Defaults to open on desktop, closed on small screens. */
  defaultOpen?: boolean
  /** Fired when the nav requests open/close (burger, Escape, scrim). */
  onOpenChange?: ((open: boolean) => void) | undefined
  className?: string | undefined
}

/**
 * App shell: composes a header + side navigation + main content into one
 * sticky-header, full-height-nav, single-scroll-container layout (#11). The
 * header burger toggles the nav with an animated show/hide that honors
 * `prefers-reduced-motion` (via `--cascivo-motion-*`), toggles `inert` on the
 * hidden nav so it leaves the tab order, and renders a mobile drawer + scrim
 * (#12). Below `lg` (64rem) the nav is an overlay drawer; at `lg`+ it is an
 * in-flow column whose width animates between its open width and 0.
 *
 * Rail vs full-hide reconcile cleanly: AppShell owns the full show/hide (this
 * `open` state); the SideNav you pass owns its own rail collapse
 * (`showCollapseToggle`). They compose on different axes and never fight.
 */
export function AppShell({
  header,
  nav,
  children,
  footer,
  open,
  defaultOpen,
  onOpenChange,
  className,
}: AppShellProps) {
  useSignals()
  const controlled = open !== undefined
  const isOpen = useSignal(open ?? defaultOpen ?? true)
  // Sync a controlled prop into the signal during render (no-op if unchanged).
  if (controlled) isOpen.value = open

  const navWrapperRef = useRef<HTMLDivElement>(null)
  const toggleOriginRef = useRef<HTMLElement | null>(null)

  function setOpen(next: boolean) {
    if (!controlled) isOpen.value = next
    onOpenChange?.(next)
  }
  function toggle() {
    if (typeof document !== 'undefined') {
      toggleOriginRef.current = document.activeElement as HTMLElement | null
    }
    setOpen(!isOpen.value)
  }

  // Uncontrolled: start closed on small screens so the drawer isn't open on load.
  useSignalEffect(() => {
    if (controlled || defaultOpen !== undefined) return
    if (typeof window === 'undefined' || typeof window.matchMedia !== 'function') return
    if (window.matchMedia('(max-width: 63.999rem)').matches) isOpen.value = false
  })

  // Escape closes the nav (drawer) — read the signal so the effect re-subscribes.
  useSignalEffect(() => {
    if (!isOpen.value || typeof document === 'undefined') return
    const onKey = (e: globalThis.KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false)
    }
    document.addEventListener('keydown', onKey)
    return () => document.removeEventListener('keydown', onKey)
  })

  // inert + focus management: when closed the nav leaves the tab order; on the
  // mobile drawer, move focus in on open and restore it to the toggle on close.
  useSignalEffect(() => {
    const wrapper = navWrapperRef.current
    if (!wrapper) return
    if (isOpen.value) {
      wrapper.removeAttribute('inert')
    } else {
      wrapper.setAttribute('inert', '')
      const origin = toggleOriginRef.current
      if (origin && wrapper.contains(document.activeElement)) origin.focus()
    }
  })

  const headerEl =
    isValidElement(header) && nav
      ? cloneElement(header as ReactElement<HeaderMenuProps>, {
          onMenuClick: toggle,
          menuExpanded: isOpen.value,
        })
      : header

  return (
    <div className={cn(styles['shell'], className)} data-open={isOpen.value}>
      <div className={styles['header']}>{headerEl}</div>
      <div className={styles['body']}>
        {nav && (
          <>
            <div
              ref={navWrapperRef}
              className={styles['navWrapper']}
              data-open={isOpen.value}
              data-testid="app-shell-nav"
            >
              <div className={styles['navInner']}>{nav}</div>
            </div>
            <div
              className={styles['scrim']}
              data-open={isOpen.value}
              data-testid="app-shell-scrim"
              aria-hidden="true"
              onClick={() => setOpen(false)}
            />
          </>
        )}
        <main id="cascade-main" tabIndex={-1} className={styles['main']}>
          {children}
        </main>
      </div>
      {footer && <div className={styles['footer']}>{footer}</div>}
    </div>
  )
}

@layer cascivo.component {
  /* Outer: one viewport-tall, non-scrolling flex column. The header is pinned
     (first, non-growing row); the body holds the only scroll container. */
  .shell {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    block-size: 100vh; /* fallback for browsers without dvh */
    block-size: 100dvh;
    overflow: hidden;
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-foreground);
    background-color: var(--cascivo-color-background);
  }

  .header {
    flex: 0 0 auto;
    z-index: var(--cascivo-z-raised);
  }

  .body {
    position: relative; /* anchors the mobile drawer + scrim */
    flex: 1 1 auto;
    min-block-size: 0; /* let children own the scroll instead of growing the row */
    display: flex;
  }

  /* Base (mobile-first, < lg): the nav is an off-canvas drawer that slides in
     over the content. It never uses display:none, so it stays in the a11y tree
     and is reachable when open; `inert` (set in JS when closed) removes it from
     the tab order. */
  .navWrapper {
    position: absolute;
    inset-block: 0;
    inset-inline-start: 0;
    z-index: var(--cascivo-z-overlay);
    block-size: 100%;
    overflow: hidden;
    transform: translateX(-100%);
    transition: transform var(--cascivo-motion-emphasis);
  }

  .navWrapper[data-open='true'] {
    transform: translateX(0);
  }

  /* RTL: the drawer enters from the inline-end side. */
  :dir(rtl) .navWrapper {
    transform: translateX(100%);
  }

  :dir(rtl) .navWrapper[data-open='true'] {
    transform: translateX(0);
  }

  /* navInner is pinned to the nav's own width so, while the wrapper width
     animates to 0 (desktop), the contents clip/slide rather than reflow. */
  .navInner {
    display: flex;
    block-size: 100%;
    inline-size: var(--cascivo-shell-panel-inline-size, 20rem);
  }

  .navInner > * {
    flex: 1 1 auto;
    min-block-size: 0;
  }

  /* Scrim: only visible behind the open drawer on small screens. */
  .scrim {
    position: absolute;
    inset: 0;
    z-index: var(--cascivo-z-dropdown);
    background-color: oklch(0 0 0 / 0.4);
    opacity: 0;
    visibility: hidden;
    transition:
      opacity var(--cascivo-motion-emphasis),
      visibility var(--cascivo-motion-emphasis);
  }

  .scrim[data-open='true'] {
    opacity: 1;
    visibility: visible;
  }

  .main {
    flex: 1 1 auto;
    min-inline-size: 0;
    overflow-y: auto; /* the single scroll container */
  }

  .footer {
    flex: 0 0 auto;
  }

  /* Desktop (>= lg, 64rem): the nav becomes an in-flow column. Full-hide
     animates the wrapper's inline-size between its open width and 0 (explicit
     lengths — never the grid 1fr→0fr trick, which silently fails on an
     auto-width flex item). The pinned navInner clips as the wrapper closes. */
  @media (min-width: 64rem) {
    .navWrapper {
      position: static;
      z-index: auto;
      inline-size: var(--cascivo-shell-aside-inline-size, 18rem);
      transform: none;
      transition: inline-size var(--cascivo-motion-emphasis);
    }

    .navWrapper[data-open='false'] {
      inline-size: 0;
    }

    .navInner {
      inline-size: var(--cascivo-shell-aside-inline-size, 18rem);
    }

    :dir(rtl) .navWrapper,
    :dir(rtl) .navWrapper[data-open='true'] {
      transform: none;
    }

    /* No scrim on desktop — the sidebar sits beside the content. */
    .scrim {
      display: none;
    }
  }
}
